values
('additional-maths:3-2-circles-tangents-and-normals:tf:f1d2c7ed', 'additional-maths', 'additional-maths:3-2-circles-tangents-and-normals', '3.2 Circles, Tangents and Normals', 'tf', 'tf', 1, '{"question": "The normal to a circle at a point passes through the centre of the circle."}'::jsonb, '{"answer": true, "explain": "The normal lies along the radius, which joins the point of contact to the centre. ✓"}'::jsonb),
('additional-maths:3-2-circles-tangents-and-normals:tf:2b2e8f48', 'additional-maths', 'additional-maths:3-2-circles-tangents-and-normals', '3.2 Circles, Tangents and Normals', 'tf', 'tf', 1, '{"question": "At the point of contact, the tangent is perpendicular to the radius."}'::jsonb, '{"answer": true, "explain": "This is the key circle fact — it gives the tangent gradient as the negative reciprocal of the radius gradient."}'::jsonb),
('additional-maths:3-2-circles-tangents-and-normals:tf:d1ff6a2d', 'additional-maths', 'additional-maths:3-2-circles-tangents-and-normals', '3.2 Circles, Tangents and Normals', 'tf', 'tf', 1, '{"question": "If a line substituted into a circle gives a quadratic with a positive discriminant, the line is a tangent."}'::jsonb, '{"answer": false, "explain": "A positive discriminant means two intersection points (a chord); a tangent needs the discriminant to be exactly \\( 0 \\)."}'::jsonb),
('additional-maths:3-2-circles-tangents-and-normals:tf:020833cf', 'additional-maths', 'additional-maths:3-2-circles-tangents-and-normals', '3.2 Circles, Tangents and Normals', 'tf', 'tf', 1, '{"question": "The centre of \\( x^2 + y^2 - 6x + 4y - 12 = 0 \\) is \\( (3,\\ -2) \\)."}'::jsonb, '{"answer": true, "explain": "Completing the square gives \\( (x-3)^2 + (y+2)^2 = 25 \\); centre \\( (3,-2) \\), radius \\( 5 \\). ✓"}'::jsonb),
('additional-maths:3-2-circles-tangents-and-normals:tf:05358434', 'additional-maths', 'additional-maths:3-2-circles-tangents-and-normals', '3.2 Circles, Tangents and Normals', 'tf', 'tf', 1, '{"question": "The tangent''s gradient equals the gradient of the radius to the point of contact."}'::jsonb, '{"answer": false, "explain": "It is the negative reciprocal of the radius gradient; the radius gradient is what the normal uses."}'::jsonb),
('additional-maths:3-2-circles-tangents-and-normals:learn:a4f082bc', 'additional-maths', 'additional-maths:3-2-circles-tangents-and-normals', '3.2 Circles, Tangents and Normals', 'learn', 'mcq', 1, '{"readingTitle": "What is the general equation of a circle?", "reading": "<p>Every point on a circle is the same distance — the <strong>radius</strong> \\( r \\) — from a fixed <strong>centre</strong> \\( (a,\\ b) \\). Applying the distance formula gives the <strong>general equation of a circle</strong>: \\[ (x - a)^2 + (y - b)^2 = r^2. \\]</p>\n            <svg viewBox=\"0 0 240 220\" width=\"100%\" style=\"max-width:280px;height:auto;display:block;margin:14px auto\" role=\"img\" aria-label=\"A circle with centre C, a radius drawn to a point P, and the tangent line touching the circle at P at a right angle to the radius\">\n              <circle cx=\"120\" cy=\"120\" r=\"70\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n              <line x1=\"120\" y1=\"120\" x2=\"169.5\" y2=\"70.5\" stroke=\"currentColor\" stroke-width=\"1.5\"/>\n              <line x1=\"124.5\" y1=\"25.5\" x2=\"214.5\" y2=\"115.5\" stroke=\"currentColor\" stroke-width=\"2\" stroke-dasharray=\"5 4\"/>\n              <circle cx=\"120\" cy=\"120\" r=\"3.5\" fill=\"currentColor\"/>\n              <circle cx=\"169.5\" cy=\"70.5\" r=\"3.5\" fill=\"currentColor\"/>\n              <text x=\"112\" y=\"134\" font-size=\"13\" fill=\"currentColor\">C(a, b)</text>\n              <text x=\"176\" y=\"66\" font-size=\"13\" fill=\"currentColor\">P</text>\n              <text x=\"138\" y=\"88\" font-size=\"13\" fill=\"currentColor\">r</text>\n              <text x=\"150\" y=\"30\" font-size=\"12\" fill=\"currentColor\">tangent</text>\n            </svg>\n            <ul>\n              <li>You read the centre off <strong>straight from the brackets</strong>: \\( (x - a)^2 \\) gives \\( x = a \\), \\( (y - b)^2 \\) gives \\( y = b \\). Watch the signs — \\( (x + 3)^2 = (x - (-3))^2 \\), so the centre is at \\( -3 \\).</li>\n              <li>The right-hand side is \\( r^2 \\), <strong>not</strong> \\( r \\). For \\( = 25 \\) the radius is \\( 5 \\); for \\( = 20 \\) it is \\( \\sqrt{20} = 2\\sqrt{5} \\).</li>\n              <li><strong>New at this level:</strong> at GCSE you only met circles centred at the origin, \\( x^2 + y^2 = r^2 \\). That is just the special case \\( a = b = 0 \\).</li>\n            </ul>\n            <p><strong>Example:</strong> \\( (x - 2)^2 + (y + 3)^2 = 49 \\) is a circle with centre \\( (2,\\ -3) \\) and radius \\( 7 \\).</p>", "question": "What are the centre and radius of \\( (x + 4)^2 + (y - 1)^2 = 9 \\)?", "options": ["Centre \\( (-4,\\ 1) \\), radius \\( 3 \\)", "Centre \\( (4,\\ -1) \\), radius \\( 3 \\)", "Centre \\( (-4,\\ 1) \\), radius \\( 9 \\)", "Centre \\( (4,\\ 1) \\), radius \\( 3 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( (x+4)^2 = (x-(-4))^2 \\) so \\( a=-4 \\); \\( (y-1)^2 \\) so \\( b=1 \\); and \\( r=\\sqrt{9}=3 \\)."}'::jsonb),
('additional-maths:3-2-circles-tangents-and-normals:learn:52f74c36', 'additional-maths', 'additional-maths:3-2-circles-tangents-and-normals', '3.2 Circles, Tangents and Normals', 'learn', 'mcq', 1, '{"readingTitle": "How do you write a circle''s equation from the information given?", "reading": "<p>You are usually given one of three things. In every case you are hunting for the <strong>centre</strong> \\( (a,\\ b) \\) and \\( r^2 \\).</p>\n            <p><strong>1. Centre and radius given</strong> — substitute straight in. Centre \\( (3,\\ -1) \\), radius \\( 4 \\): \\[ (x - 3)^2 + (y + 1)^2 = 16. \\]</p>\n            <p><strong>2. Centre and a point on the circle given</strong> — the radius is the distance from the centre to that point, so find \\( r^2 \\) with the distance formula (no need to square-root).</p>\n            <table class=\"worked\">\n              <tr><td>Centre \\( (1,\\ 2) \\), passing through \\( (4,\\ 6) \\).</td></tr>\n              <tr><td>1. \\( r^2 = (4 - 1)^2 + (6 - 2)^2 = 9 + 16 = 25 \\).</td></tr>\n              <tr><td>2. So \\( (x - 1)^2 + (y - 2)^2 = 25 \\).</td></tr>\n            </table>\n            <p><strong>3. The two ends of a diameter given</strong> — the <strong>centre is the midpoint</strong> of the diameter, and the <strong>radius is half the diameter</strong>.</p>\n            <svg viewBox=\"0 0 260 200\" width=\"100%\" style=\"max-width:300px;height:auto;display:block;margin:14px auto\" role=\"img\" aria-label=\"A circle with a diameter drawn between two endpoints A and B, its centre marked at the midpoint\">\n              <circle cx=\"130\" cy=\"100\" r=\"75\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n              <line x1=\"65\" y1=\"137.5\" x2=\"195\" y2=\"62.5\" stroke=\"currentColor\" stroke-width=\"1.5\"/>\n              <circle cx=\"65\" cy=\"137.5\" r=\"3.5\" fill=\"currentColor\"/>\n              <circle cx=\"195\" cy=\"62.5\" r=\"3.5\" fill=\"currentColor\"/>\n              <circle cx=\"130\" cy=\"100\" r=\"3.5\" fill=\"currentColor\"/>\n              <text x=\"46\" y=\"152\" font-size=\"13\" fill=\"currentColor\">A</text>\n              <text x=\"200\" y=\"60\" font-size=\"13\" fill=\"currentColor\">B</text>\n              <text x=\"112\" y=\"118\" font-size=\"12\" fill=\"currentColor\">centre</text>\n            </svg>\n            <table class=\"worked\">\n              <tr><td>Diameter from \\( A(-1,\\ 2) \\) to \\( B(5,\\ 8) \\).</td></tr>\n              <tr><td>1. Centre \\( = \\left( \\tfrac{-1 + 5}{2},\\ \\tfrac{2 + 8}{2} \\right) = (2,\\ 5) \\).</td></tr>\n              <tr><td>2. \\( r^2 = (2 - (-1))^2 + (5 - 2)^2 = 9 + 9 = 18 \\).</td></tr>\n              <tr><td>3. So \\( (x - 2)^2 + (y - 5)^2 = 18 \\).</td></tr>\n            </table>", "question": "A circle has centre \\( (0,\\ 4) \\) and passes through \\( (3,\\ 0) \\). What is its equation?", "options": ["\\( x^2 + (y - 4)^2 = 25 \\)", "\\( x^2 + (y - 4)^2 = 5 \\)", "\\( x^2 + (y + 4)^2 = 25 \\)", "\\( (x - 3)^2 + y^2 = 25 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( r^2 = (3-0)^2 + (0-4)^2 = 9 + 16 = 25 \\); centre \\( (0,4) \\) gives \\( x^2 + (y-4)^2 = 25 \\)."}'::jsonb),
('additional-maths:3-2-circles-tangents-and-normals:learn:1948ca55', 'additional-maths', 'additional-maths:3-2-circles-tangents-and-normals', '3.2 Circles, Tangents and Normals', 'learn', 'mcq', 1, '{"readingTitle": "How do you find the centre and radius by completing the square?", "reading": "<p>A circle is often given in the <strong>expanded form</strong> \\[ x^2 + y^2 + 2gx + 2fy + c = 0. \\] To recover the centre and radius, <strong>complete the square separately in \\( x \\) and in \\( y \\)</strong>, then move the numbers across.</p>\n            <table class=\"worked\">\n              <tr><td>Find the centre and radius of \\( x^2 + y^2 - 6x + 4y - 12 = 0 \\).</td></tr>\n              <tr><td>1. Group the terms: \\( (x^2 - 6x) + (y^2 + 4y) - 12 = 0 \\).</td></tr>\n              <tr><td>2. Complete each square: \\( (x - 3)^2 - 9 + (y + 2)^2 - 4 - 12 = 0 \\).</td></tr>\n              <tr><td>3. Tidy the constants: \\( (x - 3)^2 + (y + 2)^2 = 9 + 4 + 12 = 25 \\).</td></tr>\n              <tr><td>4. Centre \\( (3,\\ -2) \\), radius \\( \\sqrt{25} = 5 \\).</td></tr>\n            </table>\n            <p>There is a shortcut worth knowing (though completing the square is the safe, mark-scheme method): comparing with \\( x^2 + y^2 + 2gx + 2fy + c = 0 \\), the centre is \\( (-g,\\ -f) \\) and the radius is \\( \\sqrt{g^2 + f^2 - c} \\). Here \\( 2g = -6,\\ 2f = 4 \\), so \\( g = -3,\\ f = 2 \\): centre \\( (3,\\ -2) \\), radius \\( \\sqrt{9 + 4 + 12} = 5 \\). ✓</p>", "question": "Find the centre of \\( x^2 + y^2 - 8x + 2y - 8 = 0 \\).", "options": ["\\( (4,\\ -1) \\)", "\\( (-4,\\ 1) \\)", "\\( (8,\\ -2) \\)", "\\( (-8,\\ 2) \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( (x-4)^2 - 16 + (y+1)^2 - 1 - 8 = 0 \\Rightarrow (x-4)^2 + (y+1)^2 = 25 \\); centre \\( (4,-1) \\)."}'::jsonb),
('additional-maths:3-2-circles-tangents-and-normals:learn:029ae3b1', 'additional-maths', 'additional-maths:3-2-circles-tangents-and-normals', '3.2 Circles, Tangents and Normals', 'learn', 'mcq', 1, '{"readingTitle": "How do you find the tangent to a circle at a point on it?", "reading": "<p>A <strong>tangent</strong> touches the circle at exactly one point. The key geometry fact: the <strong>radius drawn to the point of contact is perpendicular to the tangent</strong> there. So the tangent gradient is the <strong>negative reciprocal</strong> of the radius gradient.</p>\n            <table class=\"worked\">\n              <tr><td>Find the tangent to \\( (x - 2)^2 + (y - 1)^2 = 25 \\) at the point \\( P(5,\\ 5) \\).</td></tr>\n              <tr><td>1. Check \\( P \\) is on the circle: \\( (5-2)^2 + (5-1)^2 = 9 + 16 = 25 \\). ✓</td></tr>\n              <tr><td>2. Radius gradient (centre \\( (2,1) \\) to \\( P \\)): \\( \\dfrac{5 - 1}{5 - 2} = \\dfrac{4}{3} \\).</td></tr>\n              <tr><td>3. Tangent gradient \\( = \\) negative reciprocal \\( = -\\dfrac{3}{4} \\).</td></tr>\n              <tr><td>4. Through \\( P(5,5) \\): \\( y - 5 = -\\tfrac{3}{4}(x - 5) \\), i.e. \\( 3x + 4y = 35 \\).</td></tr>\n            </table>\n            <p>Use \\( y - y_1 = m(x - x_1) \\) with the point of contact — it is faster and less error-prone than \\( y = mx + c \\).</p>", "question": "The radius to the point of contact has gradient \\( 2 \\). What is the tangent''s gradient there?", "options": ["\\( -\\tfrac{1}{2} \\)", "\\( 2 \\)", "\\( \\tfrac{1}{2} \\)", "\\( -2 \\)"]}'::jsonb, '{"answer": 0, "explain": "The tangent is perpendicular to the radius, so its gradient is the negative reciprocal of \\( 2 \\), which is \\( -\\tfrac{1}{2} \\)."}'::jsonb),
('additional-maths:3-2-circles-tangents-and-normals:learn:ee9f4583', 'additional-maths', 'additional-maths:3-2-circles-tangents-and-normals', '3.2 Circles, Tangents and Normals', 'learn', 'mcq', 1, '{"readingTitle": "How do you find the normal to a circle at a point?", "reading": "<p>The <strong>normal</strong> at a point is the line perpendicular to the tangent there. For a circle this is beautifully simple: because the radius is already perpendicular to the tangent, <strong>the normal lies along the radius — it passes through the centre.</strong></p>\n            <ul>\n              <li>So the normal at \\( P \\) is just the straight line through \\( P \\) and the <strong>centre</strong> \\( C \\).</li>\n              <li>Its gradient equals the <strong>radius gradient</strong> (the same \\( CP \\) gradient you found for the tangent) — <em>not</em> the negative reciprocal.</li>\n              <li>The word \"normal\" is <strong>new at this level</strong> for circles; at GCSE you only found tangents.</li>\n            </ul>\n            <table class=\"worked\">\n              <tr><td>Normal to \\( (x - 2)^2 + (y - 1)^2 = 25 \\) at \\( P(5,\\ 5) \\).</td></tr>\n              <tr><td>1. It passes through \\( P \\) and the centre \\( (2,\\ 1) \\).</td></tr>\n              <tr><td>2. Gradient \\( = \\dfrac{5 - 1}{5 - 2} = \\dfrac{4}{3} \\) (the radius gradient).</td></tr>\n              <tr><td>3. \\( y - 5 = \\tfrac{4}{3}(x - 5) \\), i.e. \\( 4x - 3y = 5 \\).</td></tr>\n            </table>\n            <p>Quick check: the centre \\( (2,1) \\) must satisfy it — \\( 4(2) - 3(1) = 8 - 3 = 5 \\). ✓</p>", "question": "Which statement about the normal to a circle at a point is true?", "options": ["It passes through the centre of the circle", "It is perpendicular to the radius", "It is the same line as the tangent", "It never meets the centre"]}'::jsonb, '{"answer": 0, "explain": "The normal runs along the radius, so it passes through the centre; its gradient equals the radius gradient."}'::jsonb),
('additional-maths:3-2-circles-tangents-and-normals:learn:4d9d5e18', 'additional-maths', 'additional-maths:3-2-circles-tangents-and-normals', '3.2 Circles, Tangents and Normals', 'learn', 'mcq', 1, '{"readingTitle": "How do you test where a line meets a circle — and when is it a tangent?", "reading": "<p><strong>Substitute the line into the circle equation.</strong> That eliminates one variable and leaves a <strong>quadratic</strong>; the number of real solutions is the number of intersection points, and the <strong>discriminant</strong> \\( b^2 - 4ac \\) tells you which case you are in.</p>\n            <ul>\n              <li>\\( b^2 - 4ac > 0 \\): two solutions — the line is a <strong>chord</strong> (cuts the circle twice).</li>\n              <li>\\( b^2 - 4ac = 0 \\): one repeated solution — the line is a <strong>tangent</strong> (touches once).</li>\n              <li>\\( b^2 - 4ac < 0 \\): no real solutions — the line <strong>misses</strong> the circle.</li>\n            </ul>\n            <table class=\"worked\">\n              <tr><td>For what values of \\( k \\) is \\( y = x + k \\) a tangent to \\( x^2 + y^2 = 8 \\)?</td></tr>\n              <tr><td>1. Substitute: \\( x^2 + (x + k)^2 = 8 \\).</td></tr>\n              <tr><td>2. Expand and simplify: \\( 2x^2 + 2kx + (k^2 - 8) = 0 \\).</td></tr>\n              <tr><td>3. Tangent \\( \\Rightarrow \\) repeated root \\( \\Rightarrow b^2 - 4ac = 0 \\): \\( (2k)^2 - 4(2)(k^2 - 8) = 0 \\).</td></tr>\n              <tr><td>4. \\( 4k^2 - 8k^2 + 64 = 0 \\Rightarrow k^2 = 16 \\Rightarrow k = \\pm 4 \\).</td></tr>\n            </table>\n            <p>To find the actual points of intersection instead, solve the quadratic for \\( x \\) and substitute each root back into the line to get \\( y \\).</p>", "question": "Substituting a line into a circle gives \\( x^2 - 6x + 9 = 0 \\). The line is:", "options": ["a tangent", "a chord meeting the circle twice", "missing the circle", "a diameter"]}'::jsonb, '{"answer": 0, "explain": "\\( b^2 - 4ac = 36 - 36 = 0 \\), a repeated root — exactly one point of contact, so a tangent."}'::jsonb),
('additional-maths:3-2-circles-tangents-and-normals:learn:797460bd', 'additional-maths', 'additional-maths:3-2-circles-tangents-and-normals', '3.2 Circles, Tangents and Normals', 'learn', 'mcq', 1, '{"readingTitle": "What is new here, and which facts must you just know?", "reading": "<p>This topic extends GCSE circle work; keeping the boundary straight avoids easy marks slipping away.</p>\n            <ul>\n              <li><strong>New (AS) content:</strong> the general circle \\( (x - a)^2 + (y - b)^2 = r^2 \\) with any centre; recovering the centre/radius by completing the square; and the <strong>normal</strong> to a circle. GCSE only did \\( x^2 + y^2 = r^2 \\) and tangents.</li>\n              <li><strong>MEMORISE (not on the formula sheet):</strong> the general circle equation; the distance and midpoint formulae; that perpendicular gradients multiply to \\( -1 \\); tangent \\( \\perp \\) radius; normal through the centre.</li>\n              <li><strong>Sign trap:</strong> the centre of \\( (x + a)^2 + (y + b)^2 = r^2 \\) is \\( (-a,\\ -b) \\), not \\( (a,\\ b) \\).</li>\n              <li><strong>\\( r \\) vs \\( r^2 \\) trap:</strong> the right-hand side is the radius <em>squared</em>. Take the square root — and simplify the surd — before you quote a radius.</li>\n            </ul>\n            <p>Everything else is applied straight-line geometry: gradients, perpendicularity, and \\( y - y_1 = m(x - x_1) \\), all of which carry over from 3.1.</p>", "question": "Which of these is content new to this level (not GCSE)?", "options": ["Finding the normal to a circle at a point", "The circle \\( x^2 + y^2 = r^2 \\)", "The tangent to a circle at a point", "Reading a radius off \\( x^2 + y^2 = 25 \\)"]}'::jsonb, '{"answer": 0, "explain": "The general circle, completing the square for a circle, and the normal are the new AS content; origin-centred circles and tangents were met at GCSE."}'::jsonb),
('additional-maths:3-2-circles-tangents-and-normals:misc:d5420264', 'additional-maths', 'additional-maths:3-2-circles-tangents-and-normals', '3.2 Circles, Tangents and Normals', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \\( (x + 3)^2 + (y - 4)^2 = 25 \\) has centre \\( (3,\\ 4) \\)</p><p><strong>✅ The correct idea:</strong> Read the sign carefully: \\( (x + 3)^2 = (x - (-3))^2 \\), so the centre is \\( (-3,\\ 4) \\). A weak answer copies the \\( +3 \\) as \\( 3 \\); a strong answer flips it to \\( -3 \\).</p>", "question": "Centre of \\( (x + 3)^2 + (y - 4)^2 = 25 \\)?", "options": ["\\( (-3,\\ 4) \\)", "\\( (3,\\ 4) \\)", "\\( (3,\\ -4) \\)", "\\( (-3,\\ -4) \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( (x+3)^2 \\Rightarrow a=-3 \\); \\( (y-4)^2 \\Rightarrow b=4 \\)."}'::jsonb),
('additional-maths:3-2-circles-tangents-and-normals:misc:c9750d89', 'additional-maths', 'additional-maths:3-2-circles-tangents-and-normals', '3.2 Circles, Tangents and Normals', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> For \\( (x - 1)^2 + (y - 2)^2 = 25 \\) the radius is \\( 25 \\)</p><p><strong>✅ The correct idea:</strong> The right-hand side is \\( r^2 \\), so \\( r = \\sqrt{25} = 5 \\). A weak answer quotes \\( 25 \\); a strong answer square-roots (and simplifies the surd if needed).</p>", "question": "Radius of \\( (x - 1)^2 + (y - 2)^2 = 25 \\)?", "options": ["\\( 5 \\)", "\\( 25 \\)", "\\( \\sqrt{5} \\)", "\\( 12.5 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( r = \\sqrt{r^2} = \\sqrt{25} = 5 \\)."}'::jsonb),
('additional-maths:3-2-circles-tangents-and-normals:misc:d6f3404f', 'additional-maths', 'additional-maths:3-2-circles-tangents-and-normals', '3.2 Circles, Tangents and Normals', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> The tangent gradient equals the radius gradient at the point of contact</p><p><strong>✅ The correct idea:</strong> The tangent is perpendicular to the radius, so its gradient is the negative reciprocal. A weak answer reuses the radius gradient; a strong answer flips and negates it.</p>", "question": "Radius gradient is \\( \\tfrac{3}{4} \\). Tangent gradient?", "options": ["\\( -\\tfrac{4}{3} \\)", "\\( \\tfrac{3}{4} \\)", "\\( \\tfrac{4}{3} \\)", "\\( -\\tfrac{3}{4} \\)"]}'::jsonb, '{"answer": 0, "explain": "Negative reciprocal of \\( \\tfrac{3}{4} \\) is \\( -\\tfrac{4}{3} \\)."}'::jsonb),
('additional-maths:3-2-circles-tangents-and-normals:misc:0c177672', 'additional-maths', 'additional-maths:3-2-circles-tangents-and-normals', '3.2 Circles, Tangents and Normals', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Finding the normal by taking the negative reciprocal of the radius gradient</p><p><strong>✅ The correct idea:</strong> That is the tangent. The normal runs ALONG the radius, so it has the SAME gradient as the radius and passes through the centre. A weak answer flips the gradient; a strong answer keeps the radius gradient.</p>", "question": "The normal to a circle at \\( P \\) has the same gradient as:", "options": ["the radius to \\( P \\)", "the tangent at \\( P \\)", "the \\( x \\)-axis", "no other line"]}'::jsonb, '{"answer": 0, "explain": "The normal lies along the radius, so their gradients are equal."}'::jsonb),
('additional-maths:3-2-circles-tangents-and-normals:misc:3190967c', 'additional-maths', 'additional-maths:3-2-circles-tangents-and-normals', '3.2 Circles, Tangents and Normals', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A line meets a circle in two points, so it must be a tangent</p><p><strong>✅ The correct idea:</strong> A tangent touches at ONE point (discriminant \\( = 0 \\)). Two points means a chord. A weak answer confuses the two; a strong answer checks the discriminant of the substituted quadratic.</p>", "question": "Substituting gives a quadratic with discriminant \\( > 0 \\). The line is:", "options": ["a chord (two points)", "a tangent (one point)", "missing the circle", "the diameter"]}'::jsonb, '{"answer": 0, "explain": "Positive discriminant \\( \\Rightarrow \\) two real roots \\( \\Rightarrow \\) two intersection points \\( \\Rightarrow \\) a chord."}'::jsonb),
('additional-maths:3-2-circles-tangents-and-normals:tips:cd16c0ac', 'additional-maths', 'additional-maths:3-2-circles-tangents-and-normals', '3.2 Circles, Tangents and Normals', 'tips', 'mcq', 1, '{"readingTitle": "explain — ''Show that ... perpendicular'' — finish the job", "reading": "<p><strong>0 marks:</strong> quoting the two gradients but never comparing them, or finding equations of the lines instead of gradients.</p><p><strong>Partial:</strong> correct gradients \\( 5 \\) and \\( -\\tfrac{1}{5} \\) but no conclusion.</p><p><strong>Full marks:</strong> state both gradients, show the product is \\( 5 \\times -\\tfrac{1}{5} = -1 \\), and write the concluding sentence \"so the lines are perpendicular.\" On a \"show that\" the concluding statement is itself a mark.</p>", "question": "On ''show that two lines are perpendicular'', what must you not omit?", "options": ["The concluding sentence stating they are perpendicular", "A diagram", "The equations of both lines", "The area of the triangle"]}'::jsonb, '{"answer": 0, "explain": "A ''show that'' needs every step AND the concluding statement; the conclusion carries a mark."}'::jsonb),
('additional-maths:3-2-circles-tangents-and-normals:tips:19d65e79', 'additional-maths', 'additional-maths:3-2-circles-tangents-and-normals', '3.2 Circles, Tangents and Normals', 'tips', 'mcq', 1, '{"readingTitle": "tip — Show your working on tangent/normal questions", "reading": "<p>Examiners award marks for the visible <strong>method</strong>: M1 for the radius gradient, M1 for using \\( m_1 m_2 = -1 \\) to get the tangent gradient (or reusing it for the normal), then A1 for a correct final equation via \\( y - y_1 = m(x - x_1) \\). Write each step so a single slip costs one mark, not all of them — and using \\( y - y_1 = m(x - x_1) \\) avoids the \\( c \\)-errors that \\( y = mx + c \\) invites.</p>", "question": "Why prefer \\( y - y_1 = m(x - x_1) \\) for the tangent''s equation?", "options": ["It avoids errors from finding \\( c \\) separately", "It is the only allowed form", "It gives the normal automatically", "It needs no gradient"]}'::jsonb, '{"answer": 0, "explain": "Substituting the point directly avoids a separate (error-prone) step to compute \\( c \\)."}'::jsonb),
('additional-maths:3-2-circles-tangents-and-normals:tips:65309f4b', 'additional-maths', 'additional-maths:3-2-circles-tangents-and-normals', '3.2 Circles, Tangents and Normals', 'tips', 'mcq', 1, '{"readingTitle": "explain — ''Hence'' + tangency by discriminant", "reading": "<p>When a part gives you a quadratic (often \"show that ... = 0\") and the next says \"<em>Hence</em> find \\( k \\) for which the line is a tangent\", use that quadratic — do not restart. Tangent means one repeated root, so set the <strong>discriminant \\( b^2 - 4ac = 0 \\)</strong> and solve. The 2019 examiners noted many candidates failed to link \"tangent\" to \"coincident roots\" and so scored nothing on the follow-up.</p>", "question": "A chord is a tangent when the substituted quadratic has:", "options": ["coincident (equal) roots, so \\( b^2 - 4ac = 0 \\)", "two distinct roots", "no real roots", "a positive discriminant"]}'::jsonb, '{"answer": 0, "explain": "One point of contact means a repeated root, i.e. discriminant zero."}'::jsonb),
('additional-maths:3-2-circles-tangents-and-normals:fib:640c6671', 'additional-maths', 'additional-maths:3-2-circles-tangents-and-normals', '3.2 Circles, Tangents and Normals', 'fib', 'fib', 2, '{"question": "The general equation of a circle with centre \\( (a,\\ b) \\) and radius \\( r \\) is \\( (x-a)^2 + (y-b)^2 = r^2 \\). For \\( (x-3)^2 + (y+2)^2 = 25 \\), the centre is ___B1___ and the radius is ___B2___.", "blankOptions": {"B1": ["zero", "half", "(3, -2)", "(-3, 2)"], "B2": ["negative reciprocal", "normal", "5", "zero"]}}'::jsonb, '{"blanks": {"B1": "(3, -2)", "B2": "5"}}'::jsonb),
