('additional-maths:3-3-sketching-and-plotting-graphs:mcq:869690f4', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'mcq', 'mcq', 1, '{"question": "Which command word asks for an accurate graph plotted on the grid?", "options": ["Plot", "Sketch", "Describe", "Estimate"]}'::jsonb, '{"answer": 0, "explain": "\"Plot\" means work out and mark exact points, then join smoothly. \"Sketch\" is a freehand main-features graph."}'::jsonb),
