('additional-maths:3-3-sketching-and-plotting-graphs:mcq:43fe5076', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'mcq', 'mcq', 1, '{"question": "A cubic with a repeated factor \\( (x-2)^2 \\) does what at \\( x = 2 \\)?", "options": ["Touches the \\( x \\)-axis and turns back", "Crosses the \\( x \\)-axis steeply", "Has a vertical asymptote", "Jumps discontinuously"]}'::jsonb, '{"answer": 0, "explain": "A squared (repeated) factor makes the curve touch the axis rather than cross it."}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:mcq:c6514fc6', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'mcq', 'mcq', 1, '{"question": "At which angle does \\( y = \\sin x \\) reach its maximum value of \\( 1 \\) between \\( 0^\\circ \\) and \\( 360^\\circ \\)?", "options": ["\\( 90^\\circ \\)", "\\( 0^\\circ \\)", "\\( 180^\\circ \\)", "\\( 270^\\circ \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( \\sin x \\) peaks at \\( 90^\\circ \\). At \\( 0^\\circ \\) it is \\( 0 \\); \\( \\cos x \\) is the one that starts at its maximum."}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:mcq:31217ca4', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'mcq', 'mcq', 1, '{"question": "Which statement about \\( y = \\cos x \\) on \\( 0^\\circ \\le x \\le 360^\\circ \\) is correct?", "options": ["It starts at \\( 1 \\), is \\( 0 \\) at \\( 90^\\circ \\), and \\( -1 \\) at \\( 180^\\circ \\)", "It starts at \\( 0 \\) and peaks at \\( 90^\\circ \\)", "It starts at \\( -1 \\) at \\( 0^\\circ \\)", "It has no value at \\( 90^\\circ \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( \\cos 0^\\circ = 1,\\ \\cos 90^\\circ = 0,\\ \\cos 180^\\circ = -1 \\). Option 2 describes \\( \\sin x \\), not \\( \\cos x \\)."}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:mcq:14636fa1', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'mcq', 'mcq', 1, '{"question": "The graph of \\( y = \\tan x \\) has vertical asymptotes at:", "options": ["\\( 90^\\circ \\) and \\( 270^\\circ \\)", "\\( 0^\\circ \\) and \\( 180^\\circ \\)", "\\( 45^\\circ \\) and \\( 135^\\circ \\)", "It has no asymptotes"]}'::jsonb, '{"answer": 0, "explain": "\\( \\tan x = \\sin x / \\cos x \\) is undefined where \\( \\cos x = 0 \\), i.e. at \\( 90^\\circ \\) and \\( 270^\\circ \\)."}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:mcq:58010fb9', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'mcq', 'mcq', 1, '{"question": "For \\( y = -x^2 + 4 \\), which way does the parabola open and where is its turning point?", "options": ["Opens downwards; maximum at \\( (0,\\ 4) \\)", "Opens upwards; minimum at \\( (0,\\ 4) \\)", "Opens downwards; minimum at \\( (4,\\ 0) \\)", "Opens upwards; maximum at \\( (0,\\ -4) \\)"]}'::jsonb, '{"answer": 0, "explain": "The \\( x^2 \\) coefficient is negative, so it opens downwards with a maximum; the vertex is \\( (0,\\ 4) \\)."}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:mcq:31cb7cca', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'mcq', 'mcq', 1, '{"question": "For a polynomial with a positive leading term of even degree (e.g. \\( +x^2 \\)), the ends of the graph:", "options": ["Both go up (to \\( +\\infty \\)) as \\( x \\to \\pm\\infty \\)", "Both go down", "One up, one down", "Level off to an asymptote"]}'::jsonb, '{"answer": 0, "explain": "A positive even-degree leading term sends both ends to \\( +\\infty \\); a positive odd-degree (cubic) leading term sends one end down and one up."}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:mcq:86eb7b47', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'mcq', 'mcq', 1, '{"question": "You plot \\( y = x^2 \\) and \\( y = x + 6 \\) on the same grid and they cross at \\( x = -2 \\) and \\( x = 3 \\). These \\( x \\)-values are the solutions of:", "options": ["\\( x^2 = x + 6 \\)", "\\( x^2 + x + 6 = 0 \\)", "\\( x = 6 \\)", "\\( 2x = 6 \\)"]}'::jsonb, '{"answer": 0, "explain": "Where the curves cross, the two expressions are equal: \\( x^2 = x + 6 \\). Its solutions are the crossing \\( x \\)-values."}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:mcq:a2e3d32d', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'mcq', 'mcq', 1, '{"question": "A curve is plotted from a table of values. How should the points be joined?", "options": ["With a single smooth curve", "With ruled straight segments between each pair", "With a dotted box around them", "Left as separate dots"]}'::jsonb, '{"answer": 0, "explain": "Plotted curve points are joined by one smooth freehand curve; straight segments lose the curve mark. (Only genuinely linear graphs are ruled.)"}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:tf:a1b55a78', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'tf', 'tf', 1, '{"question": "The command word \"sketch\" means you must plot exact points accurately to scale."}'::jsonb, '{"answer": false, "explain": "\"Sketch\" is freehand and not to scale — it must show the main features (shape, intercepts, asymptotes, turning points) but not accurately plotted points."}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:tf:134964e7', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'tf', 'tf', 1, '{"question": "The graph of \\( y = 2^x \\) has the \\( x \\)-axis (\\( y = 0 \\)) as a horizontal asymptote."}'::jsonb, '{"answer": true, "explain": "As \\( x \\to -\\infty \\) the curve approaches \\( y = 0 \\) without ever reaching it — an asymptote."}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:tf:6e6c9cd6', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'tf', 'tf', 1, '{"question": "The graph of \\( y = \\sin x \\) has amplitude \\( 360^\\circ \\)."}'::jsonb, '{"answer": false, "explain": "Its amplitude (peak height) is \\( 1 \\); \\( 360^\\circ \\) is its period (how often it repeats)."}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:tf:7a22c69b', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'tf', 'tf', 1, '{"question": "A cubic can have exactly two distinct real roots if one of them is repeated."}'::jsonb, '{"answer": true, "explain": "A repeated (squared) factor gives a root where the curve touches the axis, so \\( y = (x-1)^2(x+3) \\) has just two distinct roots."}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:tf:b8bb3121', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'tf', 'tf', 1, '{"question": "The graph of \\( y = \\cos x \\) passes through \\( (0^\\circ,\\ 1) \\)."}'::jsonb, '{"answer": true, "explain": "\\( \\cos 0^\\circ = 1 \\), so the cosine graph starts at its maximum on the \\( y \\)-axis."}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:tf:570ac243', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'tf', 'tf', 1, '{"question": "A parabola \\( y = ax^2 + bx + c \\) with \\( a > 0 \\) opens downwards."}'::jsonb, '{"answer": false, "explain": "A positive \\( x^2 \\) coefficient opens the parabola upwards (a minimum); a negative one opens it downwards."}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:tf:a1be8d5a', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'tf', 'tf', 1, '{"question": "When plotting a curve you should join the points with ruled straight segments."}'::jsonb, '{"answer": false, "explain": "Curve points are joined with a single smooth freehand curve; straight segments lose the smoothness mark. Only genuinely linear graphs are ruled."}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:tf:abf9b2fa', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'tf', 'tf', 1, '{"question": "The graph of \\( y = k a^x \\) always passes through \\( (0,\\ k) \\)."}'::jsonb, '{"answer": true, "explain": "At \\( x = 0 \\), \\( a^0 = 1 \\), so \\( y = k \\) whatever the value of \\( a \\)."}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:learn:5a63c5da', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'learn', 'mcq', 1, '{"readingTitle": "What is the difference between ''sketch'', ''plot'' and ''draw''?", "reading": "<p>These three command words look similar but the mark scheme treats them very differently — get the wrong one and you can lose every mark even with the right idea.</p>\n            <ul>\n              <li><strong>Sketch</strong> — a quick freehand graph showing the <strong>main features</strong>, <em>not to scale</em>. You must show the right shape, where it crosses the axes, any asymptotes and any turning points, but you do <strong>not</strong> plot exact points.</li>\n              <li><strong>Plot</strong> — an <strong>accurate</strong> graph on a printed grid: work out a table of \\( (x,\\ y) \\) points, mark each one precisely, then join them with a <strong>smooth curve</strong> (or a ruled straight line for a linear graph).</li>\n              <li><strong>Draw</strong> — like plot but with <em>reasonable</em> accuracy; used when the exact grid points matter less than a fair-looking curve.</li>\n            </ul>\n            <p>A quick rule: if the question gives you a <strong>grid</strong>, it almost always wants <em>plot</em> or <em>draw</em>; if it just says \"sketch\", a labelled freehand shape is enough.</p>", "question": "A question says \"Sketch \\( y = 2^x \\)\". What is expected?", "options": ["A labelled freehand curve showing shape, the asymptote and the y-intercept", "An accurate plot of exact points on graph paper", "A table of values only", "A ruled straight line"]}'::jsonb, '{"answer": 0, "explain": "\"Sketch\" wants the main features (shape, asymptote \\( y=0 \\), intercept), not accurately plotted points."}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:learn:cd822d11', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'learn', 'mcq', 1, '{"readingTitle": "How do you sketch a linear graph from its equation?", "reading": "<p>A <strong>linear</strong> graph \\( y = mx + c \\) is a straight line, fixed by just two facts:</p>\n            <ul>\n              <li>the <strong>gradient</strong> \\( m \\) — how steep the line is (\\( m>0 \\) slopes up to the right, \\( m<0 \\) slopes down); and</li>\n              <li>the <strong>\\( y \\)-intercept</strong> \\( c \\) — where it cuts the \\( y \\)-axis, at \\( (0,\\ c) \\).</li>\n            </ul>\n            <p><strong>Worked example — sketch \\( y = 2x - 3 \\):</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. \\( c = -3 \\): the line crosses the \\( y \\)-axis at \\( (0,\\ -3) \\).</td></tr>\n              <tr><td>2. \\( m = 2 \\): from that point go up \\( 2 \\) for every \\( 1 \\) across (a fairly steep upward line).</td></tr>\n              <tr><td>3. Find the \\( x \\)-intercept by setting \\( y = 0 \\): \\( 0 = 2x - 3 \\Rightarrow x = 1.5 \\), so it also passes through \\( (1.5,\\ 0) \\).</td></tr>\n            </table>\n            <p>Two points are enough to fix a straight line, so mark \\( (0,-3) \\) and \\( (1.5,\\ 0) \\) and rule a line through them.</p>", "question": "Where does \\( y = -3x + 6 \\) cross the \\( y \\)-axis?", "options": ["\\( (0,\\ 6) \\)", "\\( (6,\\ 0) \\)", "\\( (0,\\ -3) \\)", "\\( (2,\\ 0) \\)"]}'::jsonb, '{"answer": 0, "explain": "The \\( y \\)-intercept is \\( c = 6 \\), so the line cuts the \\( y \\)-axis at \\( (0,\\ 6) \\). (Its \\( x \\)-intercept is \\( (2,0) \\).)"}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:learn:bd0b35bb', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'learn', 'mcq', 1, '{"readingTitle": "How do you sketch a quadratic from its factorised form?", "reading": "<p>To sketch <strong>any</strong> polynomial you need four things: the <strong>roots</strong> (where it crosses the \\( x \\)-axis), the sign of the <strong>leading term</strong> (which way it opens / its long-run behaviour), the <strong>\\( y \\)-intercept</strong>, and any <strong>turning point</strong>.</p>\n            <p>A quadratic graph is a <strong>parabola</strong>. From <strong>factorised form</strong> the roots are read straight off; a positive \\( x^2 \\) coefficient opens <strong>upwards</strong> (a minimum), a negative one opens <strong>downwards</strong> (a maximum).</p>\n            <p><strong>Worked example — sketch \\( y = x^2 - 2x - 3 \\):</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. Factorise: \\( y = (x - 3)(x + 1) \\), so the roots are \\( x = 3 \\) and \\( x = -1 \\).</td></tr>\n              <tr><td>2. Leading term \\( +x^2 \\Rightarrow \\) opens upwards (a minimum).</td></tr>\n              <tr><td>3. \\( y \\)-intercept: put \\( x = 0 \\Rightarrow y = -3 \\), i.e. \\( (0,\\ -3) \\).</td></tr>\n              <tr><td>4. Turning point sits halfway between the roots, at \\( x = 1 \\); then \\( y = 1 - 2 - 3 = -4 \\), so the vertex is \\( (1,\\ -4) \\).</td></tr>\n            </table>\n            <svg viewBox=\"0 0 320 230\" width=\"100%\" style=\"max-width:360px;height:auto;display:block;margin:14px auto\" role=\"img\" aria-label=\"Upward parabola through x = minus 1 and x = 3 with a minimum turning point at 1, minus 4 and y-intercept minus 3\">\n              <line x1=\"20\" y1=\"110\" x2=\"300\" y2=\"110\" stroke=\"currentColor\" stroke-width=\"1.4\"/>\n              <line x1=\"117\" y1=\"18\" x2=\"117\" y2=\"210\" stroke=\"currentColor\" stroke-width=\"1.4\"/>\n              <polygon points=\"300,110 291,106 291,114\" fill=\"currentColor\"/>\n              <polygon points=\"117,18 113,27 121,27\" fill=\"currentColor\"/>\n              <polyline points=\"30,20 51.6,69.5 73.3,110 94.9,141.5 116.6,164 138.3,177.5 160,182 181.6,177.5 203.3,164 225,141.5 246.6,110 268.3,69.5 290,20\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.5\"/>\n              <circle cx=\"73.3\" cy=\"110\" r=\"3.5\" fill=\"currentColor\"/><circle cx=\"246.6\" cy=\"110\" r=\"3.5\" fill=\"currentColor\"/>\n              <circle cx=\"160\" cy=\"182\" r=\"3.5\" fill=\"currentColor\"/><circle cx=\"117\" cy=\"164\" r=\"3\" fill=\"currentColor\"/>\n              <g font-size=\"12\" fill=\"currentColor\">\n                <text x=\"70\" y=\"102\" text-anchor=\"middle\">-1</text><text x=\"250\" y=\"102\" text-anchor=\"middle\">3</text>\n                <text x=\"168\" y=\"186\">(1, -4)</text><text x=\"123\" y=\"160\">-3</text>\n                <text x=\"292\" y=\"104\" text-anchor=\"end\">x</text><text x=\"123\" y=\"26\">y</text>\n              </g>\n            </svg>\n            <p>Mark the two roots, the \\( y \\)-intercept and the vertex, then draw a smooth U through them.</p>", "question": "Sketching \\( y = (x-2)(x+4) \\), where are the roots and which way does it open?", "options": ["Roots \\( x=2 \\) and \\( x=-4 \\); opens upwards", "Roots \\( x=-2 \\) and \\( x=4 \\); opens upwards", "Roots \\( x=2 \\) and \\( x=-4 \\); opens downwards", "Roots \\( x=2 \\) and \\( x=4 \\); opens upwards"]}'::jsonb, '{"answer": 0, "explain": "Roots make each bracket zero: \\( x=2,\\ x=-4 \\). The \\( x^2 \\) coefficient is \\( +1 \\), so it opens upwards."}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:learn:d1a79f00', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'learn', 'mcq', 1, '{"readingTitle": "How do you sketch a cubic, and what does a repeated root do?", "reading": "<p>A <strong>cubic</strong> \\( y = ax^3 + \\dots \\) has a characteristic <strong>S-shape</strong> and up to <strong>three</strong> \\( x \\)-intercepts. The sign of the leading term sets the long-run behaviour:</p>\n            <ul>\n              <li>\\( a > 0 \\): the curve comes up from bottom-left and heads to top-right (as \\( x \\to -\\infty,\\ y \\to -\\infty \\); as \\( x \\to +\\infty,\\ y \\to +\\infty \\)).</li>\n              <li>\\( a < 0 \\): the whole shape is flipped (top-left down to bottom-right).</li>\n            </ul>\n            <p><strong>Worked example — sketch \\( y = x(x-2)(x+2) \\):</strong> roots at \\( x = -2,\\ 0,\\ 2 \\); leading term \\( +x^3 \\), so it rises overall and weaves through all three roots:</p>\n            <svg viewBox=\"0 0 320 230\" width=\"100%\" style=\"max-width:360px;height:auto;display:block;margin:14px auto\" role=\"img\" aria-label=\"Positive cubic curve crossing the x-axis at minus 2, 0 and 2 with an S-shape rising from bottom-left to top-right\">\n              <line x1=\"20\" y1=\"115\" x2=\"300\" y2=\"115\" stroke=\"currentColor\" stroke-width=\"1.4\"/>\n              <line x1=\"160\" y1=\"20\" x2=\"160\" y2=\"210\" stroke=\"currentColor\" stroke-width=\"1.4\"/>\n              <polygon points=\"300,115 291,111 291,119\" fill=\"currentColor\"/>\n              <polygon points=\"160,20 156,29 164,29\" fill=\"currentColor\"/>\n              <polyline points=\"30,199.4 56,115 82,75.6 108,70 134,87 160,115 186,143 212,160 238,154.4 264,115 290,30.6\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.5\"/>\n              <circle cx=\"56\" cy=\"115\" r=\"3.5\" fill=\"currentColor\"/><circle cx=\"160\" cy=\"115\" r=\"3.5\" fill=\"currentColor\"/><circle cx=\"264\" cy=\"115\" r=\"3.5\" fill=\"currentColor\"/>\n              <g font-size=\"12\" fill=\"currentColor\">\n                <text x=\"52\" y=\"131\" text-anchor=\"middle\">-2</text><text x=\"150\" y=\"131\" text-anchor=\"middle\">0</text><text x=\"268\" y=\"131\" text-anchor=\"middle\">2</text>\n                <text x=\"292\" y=\"109\" text-anchor=\"end\">x</text><text x=\"166\" y=\"28\">y</text>\n              </g>\n            </svg>\n            <p>A <strong>repeated root</strong> changes the picture: a squared factor such as \\( (x-1)^2 \\) makes the curve <strong>touch</strong> the \\( x \\)-axis at \\( x = 1 \\) and turn back, rather than crossing it. So \\( y = (x-1)^2(x+2) \\) touches at \\( x = 1 \\) and crosses at \\( x = -2 \\) — two distinct roots, not three.</p>", "question": "How does the graph of \\( y = (x+3)^2(x-1) \\) behave at \\( x = -3 \\)?", "options": ["It touches the \\( x \\)-axis (repeated root) and turns back", "It crosses the \\( x \\)-axis steeply", "It has an asymptote there", "It is undefined there"]}'::jsonb, '{"answer": 0, "explain": "The squared factor \\( (x+3)^2 \\) gives a repeated root, so the curve touches the axis at \\( x=-3 \\) rather than crossing."}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:learn:503bdc39', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'learn', 'mcq', 1, '{"readingTitle": "What do the graphs of sin, cos and tan look like from 0° to 360°?", "reading": "<p>In this qualification angles are always in <strong>degrees</strong> (never radians). You must know the shapes of the three trig graphs over \\( 0^\\circ \\) to \\( 360^\\circ \\).</p>\n            <ul>\n              <li>\\( y = \\sin x \\): a wave starting at \\( (0^\\circ,\\ 0) \\), up to a maximum \\( 1 \\) at \\( 90^\\circ \\), back to \\( 0 \\) at \\( 180^\\circ \\), down to \\( -1 \\) at \\( 270^\\circ \\), and \\( 0 \\) again at \\( 360^\\circ \\).</li>\n              <li>\\( y = \\cos x \\): the same wave shifted — it starts at a maximum \\( 1 \\) at \\( 0^\\circ \\), is \\( 0 \\) at \\( 90^\\circ \\), \\( -1 \\) at \\( 180^\\circ \\), \\( 0 \\) at \\( 270^\\circ \\), and back to \\( 1 \\) at \\( 360^\\circ \\).</li>\n              <li>Both have <strong>amplitude</strong> \\( 1 \\) (peak height) and <strong>period</strong> \\( 360^\\circ \\) (they repeat every \\( 360^\\circ \\)).</li>\n              <li>\\( y = \\tan x \\) is different: it has <strong>period</strong> \\( 180^\\circ \\), no maximum, and <strong>vertical asymptotes</strong> at \\( 90^\\circ \\) and \\( 270^\\circ \\) where it shoots off to \\( \\pm\\infty \\).</li>\n            </ul>\n            <svg viewBox=\"0 0 440 200\" width=\"100%\" style=\"max-width:480px;height:auto;display:block;margin:14px auto\" role=\"img\" aria-label=\"Graphs of y equals sin x (solid) and y equals cos x (dashed) from 0 to 360 degrees, both with amplitude 1\">\n              <line x1=\"30\" y1=\"40\" x2=\"410\" y2=\"40\" stroke=\"currentColor\" stroke-width=\"0.6\" stroke-opacity=\"0.35\" stroke-dasharray=\"3 3\"/>\n              <line x1=\"30\" y1=\"160\" x2=\"410\" y2=\"160\" stroke=\"currentColor\" stroke-width=\"0.6\" stroke-opacity=\"0.35\" stroke-dasharray=\"3 3\"/>\n              <line x1=\"30\" y1=\"100\" x2=\"410\" y2=\"100\" stroke=\"currentColor\" stroke-width=\"1.4\"/>\n              <line x1=\"40\" y1=\"20\" x2=\"40\" y2=\"185\" stroke=\"currentColor\" stroke-width=\"1.4\"/>\n              <polygon points=\"410,100 401,96 401,104\" fill=\"currentColor\"/>\n              <polyline points=\"40,100 70,70 100,48 130,40 160,48 190,70 220,100 250,130 280,152 310,160 340,152 370,130 400,100\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.4\"/>\n              <polyline points=\"40,40 70,48 100,70 130,100 160,130 190,152 220,160 250,152 280,130 310,100 340,70 370,48 400,40\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-dasharray=\"6 4\"/>\n              <g font-size=\"11\" fill=\"currentColor\" text-anchor=\"middle\">\n                <text x=\"130\" y=\"175\">90</text><text x=\"220\" y=\"175\">180</text><text x=\"310\" y=\"175\">270</text><text x=\"400\" y=\"175\">360</text>\n                <text x=\"30\" y=\"44\" text-anchor=\"end\">1</text><text x=\"30\" y=\"164\" text-anchor=\"end\">-1</text>\n                <text x=\"405\" y=\"94\" text-anchor=\"start\">x</text>\n              </g>\n              <g font-size=\"11\" fill=\"currentColor\">\n                <text x=\"70\" y=\"63\">sin</text><text x=\"300\" y=\"90\">cos</text>\n              </g>\n            </svg>\n            <p>Solid = \\( \\sin x \\), dashed = \\( \\cos x \\). Notice \\( \\cos x \\) is just \\( \\sin x \\) shifted \\( 90^\\circ \\) to the left.</p>", "question": "What are the amplitude and period of \\( y = \\cos x \\)?", "options": ["Amplitude \\( 1 \\), period \\( 360^\\circ \\)", "Amplitude \\( 360^\\circ \\), period \\( 1 \\)", "Amplitude \\( 2 \\), period \\( 180^\\circ \\)", "Amplitude \\( 1 \\), period \\( 90^\\circ \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( \\cos x \\) reaches a peak of \\( 1 \\) (amplitude) and repeats every \\( 360^\\circ \\) (period)."}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:learn:bd9a0303', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'learn', 'mcq', 1, '{"readingTitle": "What does the graph of an exponential function look like?", "reading": "<p>An <strong>exponential</strong> function \\( y = k a^x \\) (with \\( a > 0 \\), \\( k > 0 \\)) has a distinctive shape controlled by \\( a \\):</p>\n            <ul>\n              <li>If \\( a > 1 \\) the graph shows <strong>growth</strong> — it rises ever more steeply to the right.</li>\n              <li>If \\( 0 < a < 1 \\) it shows <strong>decay</strong> — it falls, flattening off towards the right.</li>\n              <li>Either way the \\( x \\)-axis, \\( y = 0 \\), is a <strong>horizontal asymptote</strong>: the curve gets closer and closer to it but <strong>never touches or crosses</strong> it.</li>\n              <li>Putting \\( x = 0 \\) gives \\( y = k a^0 = k \\), so the curve <strong>always cuts the \\( y \\)-axis at \\( (0,\\ k) \\)</strong>.</li>\n            </ul>\n            <p><strong>Worked example — sketch \\( y = 8 \\times (0.5)^x \\)</strong> (decay, \\( k = 8 \\)):</p>\n            <svg viewBox=\"0 0 300 190\" width=\"100%\" style=\"max-width:340px;height:auto;display:block;margin:14px auto\" role=\"img\" aria-label=\"Exponential decay curve starting at 0, k on the y-axis and falling towards the horizontal asymptote y = 0\">\n              <line x1=\"30\" y1=\"160\" x2=\"285\" y2=\"160\" stroke=\"currentColor\" stroke-width=\"1.4\"/>\n              <line x1=\"60\" y1=\"18\" x2=\"60\" y2=\"178\" stroke=\"currentColor\" stroke-width=\"1.4\"/>\n              <polygon points=\"285,160 276,156 276,164\" fill=\"currentColor\"/>\n              <polygon points=\"60,18 56,27 64,27\" fill=\"currentColor\"/>\n              <line x1=\"60\" y1=\"160\" x2=\"285\" y2=\"160\" stroke=\"currentColor\" stroke-width=\"1.4\" stroke-dasharray=\"5 4\" stroke-opacity=\"0.7\"/>\n              <polyline points=\"60,30 85,68 110,95 135,114 160,127.5 185,137 210,144 235,148.5 260,152\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.5\"/>\n              <circle cx=\"60\" cy=\"30\" r=\"3.5\" fill=\"currentColor\"/>\n              <g font-size=\"12\" fill=\"currentColor\">\n                <text x=\"66\" y=\"28\">(0, k)</text><text x=\"200\" y=\"152\">asymptote y = 0</text>\n                <text x=\"278\" y=\"153\" text-anchor=\"end\">x</text><text x=\"66\" y=\"26\" opacity=\"0\"> </text>\n              </g>\n            </svg>\n            <p>A <strong>growth</strong> curve (\\( a>1 \\)) is the mirror image: same \\( (0,k) \\) intercept and same \\( y=0 \\) asymptote on the left, but rising steeply to the right.</p>", "question": "For \\( y = 3 \\times 2^x \\), where does the curve cross the \\( y \\)-axis and what is its asymptote?", "options": ["Crosses at \\( (0,\\ 3) \\); asymptote \\( y = 0 \\)", "Crosses at \\( (0,\\ 2) \\); asymptote \\( y = 3 \\)", "Crosses at \\( (0,\\ 0) \\); asymptote \\( x = 0 \\)", "Crosses at \\( (0,\\ 6) \\); asymptote \\( y = 1 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( y = k a^x \\) cuts the \\( y \\)-axis at \\( (0,\\ k) = (0,\\ 3) \\); the horizontal asymptote is always \\( y = 0 \\)."}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:learn:dc214117', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'learn', 'mcq', 1, '{"readingTitle": "How do you plot a graph accurately and solve an equation from it?", "reading": "<p>When a question says <strong>plot</strong> and gives a grid, follow a fixed routine:</p>\n            <table class=\"worked\">\n              <tr><td>1. Make a <strong>table of values</strong>: choose each \\( x \\) on the grid and compute \\( y \\) (write down anything you evaluate on the calculator).</td></tr>\n              <tr><td>2. <strong>Plot each point</strong> carefully — to within half a small square.</td></tr>\n              <tr><td>3. Join them with a <strong>single smooth curve</strong> (freehand, not ruler-drawn segments) — unless it is a straight line, which you rule.</td></tr>\n            </table>\n            <p>Two graphs plotted on the <strong>same</strong> grid let you <strong>solve an equation graphically</strong>: the \\( x \\)-coordinate of a point where the curves <strong>cross</strong> is a solution. Read it off to the accuracy the question asks (often \\( 1 \\) decimal place).</p>\n            <p>The commonest error is joining plotted points with straight-line segments instead of a smooth curve. The left picture below is <strong>wrong</strong> (segments); the right is <strong>right</strong> (smooth):</p>\n            <svg viewBox=\"0 0 380 150\" width=\"100%\" style=\"max-width:420px;height:auto;display:block;margin:14px auto\" role=\"img\" aria-label=\"Left: five points joined by straight line segments, labelled wrong. Right: the same points joined by a smooth curve, labelled right\">\n              <g stroke=\"currentColor\" stroke-width=\"1.2\" stroke-opacity=\"0.4\"><line x1=\"20\" y1=\"120\" x2=\"170\" y2=\"120\"/></g>\n              <polyline points=\"30,110 65,70 100,45 135,58 160,95\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.2\"/>\n              <g fill=\"currentColor\"><circle cx=\"30\" cy=\"110\" r=\"3\"/><circle cx=\"65\" cy=\"70\" r=\"3\"/><circle cx=\"100\" cy=\"45\" r=\"3\"/><circle cx=\"135\" cy=\"58\" r=\"3\"/><circle cx=\"160\" cy=\"95\" r=\"3\"/></g>\n              <text x=\"95\" y=\"140\" text-anchor=\"middle\" font-size=\"12\" fill=\"currentColor\">✗ straight segments</text>\n              <g stroke=\"currentColor\" stroke-width=\"1.2\" stroke-opacity=\"0.4\"><line x1=\"210\" y1=\"120\" x2=\"360\" y2=\"120\"/></g>\n              <path d=\"M 220,110 Q 250,55 290,45 Q 330,40 350,95\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.2\"/>\n              <g fill=\"currentColor\"><circle cx=\"220\" cy=\"110\" r=\"3\"/><circle cx=\"255\" cy=\"70\" r=\"3\"/><circle cx=\"290\" cy=\"45\" r=\"3\"/><circle cx=\"325\" cy=\"58\" r=\"3\"/><circle cx=\"350\" cy=\"95\" r=\"3\"/></g>\n              <text x=\"285\" y=\"140\" text-anchor=\"middle\" font-size=\"12\" fill=\"currentColor\">✓ smooth curve</text>\n            </svg>\n            <p>If the question says <strong>\"Hence\"</strong>, you <em>must</em> read the answer from your graph — using the calculator''s solver instead scores <strong>0</strong>.</p>", "question": "Two graphs are plotted on one grid and cross at \\( (1.9,\\ 4) \\). What does \\( x = 1.9 \\) represent?", "options": ["A solution of the equation formed by setting the two expressions equal", "The gradient of one curve", "The \\( y \\)-intercept", "The period of the graph"]}'::jsonb, '{"answer": 0, "explain": "Where the curves cross, the two expressions are equal, so the \\( x \\)-coordinate solves the equation setting them equal."}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:misc:35711e5d', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Joining plotted curve points with a ruler, giving straight segments</p><p><strong>✅ The correct idea:</strong> A curve must be joined with one smooth freehand line. A weak answer rules segments point-to-point; a strong answer draws a single smooth curve passing within half a square of every point.</p>", "question": "How should plotted points on a curve be joined?", "options": ["With one smooth freehand curve", "With ruled straight segments", "Not joined at all", "With a dotted rectangle"]}'::jsonb, '{"answer": 0, "explain": "Curves are smooth; ruled segments lose the mark. Only straight-line graphs are ruled."}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:misc:363bca64', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Sketching \\( y = 2^x \\) so that it touches or crosses the \\( x \\)-axis</p><p><strong>✅ The correct idea:</strong> An exponential never reaches the \\( x \\)-axis — \\( y = 0 \\) is an asymptote it only approaches. A weak sketch cuts the axis; a strong sketch flattens towards \\( y = 0 \\) and shows the \\( y \\)-intercept \\( (0,\\ k) \\).</p>", "question": "What must an exponential sketch show near the \\( x \\)-axis?", "options": ["The curve approaching \\( y = 0 \\) as an asymptote", "The curve crossing \\( y = 0 \\)", "A vertical asymptote", "A turning point on the axis"]}'::jsonb, '{"answer": 0, "explain": "\\( y = 0 \\) is a horizontal asymptote; the curve gets close but never touches it."}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:misc:1ed8f047', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A quadratic sketch with no roots, vertex or intercepts labelled</p><p><strong>✅ The correct idea:</strong> A sketch is marked on its features. A weak answer is an unlabelled U; a strong answer marks the roots (\\( x \\)-intercepts), the \\( y \\)-intercept, the turning point and shows which way it opens.</p>", "question": "Which features should a quadratic sketch show?", "options": ["Roots, \\( y \\)-intercept, turning point and direction of opening", "Only the vertex", "Only the \\( y \\)-intercept", "Just a smooth U with no labels"]}'::jsonb, '{"answer": 0, "explain": "Sketch marks are for the labelled main features, not for accuracy."}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:misc:6bcdbaa2', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Sketching a cubic as if it were a parabola (one turn, up to 2 roots)</p><p><strong>✅ The correct idea:</strong> A cubic has an S-shape and up to three roots. A weak answer draws a U; a strong answer shows the curve weaving through its roots with the correct end behaviour set by the leading term.</p>", "question": "How many \\( x \\)-axis crossings can a cubic have?", "options": ["Up to three", "Exactly one always", "Up to two", "None"]}'::jsonb, '{"answer": 0, "explain": "A cubic can cross the \\( x \\)-axis up to three times (a repeated root reduces the number of distinct crossings)."}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:misc:3ff345b5', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Answering a \"Hence, from your graph\" part by using the calculator''s equation solver</p><p><strong>✅ The correct idea:</strong> \"Hence\" and \"from your graph\" require you to read the value off the plotted graph. A weak answer types it into the solver (scoring 0); a strong answer reads the crossing point to the stated accuracy.</p>", "question": "A part says \"Hence write down the root from your graph\". You should:", "options": ["Read the crossing point off your plotted graph", "Use the calculator solve function", "Factorise algebraically", "Complete the square"]}'::jsonb, '{"answer": 0, "explain": "\"Hence/from your graph\" ties you to the graph; a calculator-only answer earns no marks."}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:tips:bd679948', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'tips', 'mcq', 1, '{"readingTitle": "explain — Sketch vs plot vs draw", "reading": "<p><strong>Sketch</strong> = freehand, not to scale, show the main features (shape, intercepts, asymptotes, turning points). <strong>Plot</strong> = accurate points on the grid, joined smoothly. <strong>Draw</strong> = reasonably accurate curve. Reading the word wrongly is a classic way to lose easy marks: an accurate plot when only a sketch is needed wastes time, and a rough sketch when a plot is required scores little.</p>", "question": "The grid is provided and the word is \"plot\". You should:", "options": ["Work out a table of values and mark points accurately", "Draw a rough freehand shape", "Only describe the graph in words", "Give the equation only"]}'::jsonb, '{"answer": 0, "explain": "A provided grid + \"plot\" means an accurate table-of-values graph."}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:tips:28adde44', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'tips', 'mcq', 1, '{"readingTitle": "tip — Sketch feature checklist ladder", "reading": "<p>Build a sketch in order and you collect every B-mark:</p><p><strong>1. Shape</strong> — right family and direction (parabola up/down, cubic S, exponential curve). <strong>2. Intercepts</strong> — mark the \\( x \\)-axis roots and the \\( y \\)-intercept. <strong>3. Asymptote</strong> — for exponentials show the curve approaching \\( y = 0 \\); for \\( \\tan x \\) show the vertical asymptotes. <strong>4. Turning point</strong> — mark and label any maximum/minimum. Miss any rung and that feature mark is gone.</p>", "question": "Which feature is most often missing from an exponential sketch?", "options": ["The horizontal asymptote \\( y = 0 \\)", "The gradient value", "The period", "The amplitude"]}'::jsonb, '{"answer": 0, "explain": "Students often let the exponential touch or cross the \\( x \\)-axis, losing the asymptote feature mark."}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:tips:914e2a1c', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'tips', 'mcq', 1, '{"readingTitle": "explain — \"Hence\" means read it off the graph", "reading": "<p>When two graphs are plotted and a part says \"<em>Hence</em>\" (or \"from your graph\") solve or find a root, the \\( x \\)-coordinate of the <strong>crossing point</strong> is the answer. You <strong>must</strong> read it from the graph to the accuracy asked (often \\( 1 \\) d.p.). The 2024 examiners confirmed that answers obtained solely from the calculator''s solve function earn no credit on a \"Hence\" part.</p>", "question": "Two plotted curves cross once at \\( x \\approx 0.5 \\). A \"Hence\" part wants the root to 1 d.p. Best answer:", "options": ["\\( x = 0.5 \\), read from the graph", "Use the calculator solver for more decimals", "State there is no root", "Give the \\( y \\)-value instead"]}'::jsonb, '{"answer": 0, "explain": "Read the crossing \\( x \\)-value to 1 d.p. from the graph; a calculator-solved value scores 0 on \"Hence\"."}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:fib:a1d268de', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'fib', 'fib', 2, '{"question": "A graph drawn with only its main features, not to scale, is called a ___B1___; an accurate one worked out on a grid is a ___B2___.", "blankOptions": {"B1": ["1", "cross", "k", "sketch"], "B2": ["upwards", "downwards", "cross", "plot"]}}'::jsonb, '{"blanks": {"B1": "sketch", "B2": "plot"}}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:fib:5e3059f8', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'fib', 'fib', 2, '{"question": "For the exponential graph \\( y = k a^x \\) with \\( a > 0 \\), the horizontal asymptote is the line \\( y = \\) ___B1___ and the curve crosses the \\( y \\)-axis at the value ___B2___.", "blankOptions": {"B1": ["cross", "0", "2", "downwards"], "B2": ["1", "2", "180", "k"]}}'::jsonb, '{"blanks": {"B1": "0", "B2": "k"}}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:fib:994183c2', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'fib', 'fib', 2, '{"question": "A quadratic graph has the shape called a ___B1___; when the \\( x^2 \\) coefficient is positive it opens ___B2___.", "blankOptions": {"B1": ["cross", "1", "k", "parabola"], "B2": ["upwards", "sketch", "2", "plot"]}}'::jsonb, '{"blanks": {"B1": "parabola", "B2": "upwards"}}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:fib:34117225', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'fib', 'fib', 2, '{"question": "The graphs of \\( y = \\sin x \\) and \\( y = \\cos x \\) both repeat every ___B1___ degrees and have amplitude ___B2___.", "blankOptions": {"B1": ["k", "roots", "360", "parabola"], "B2": ["parabola", "1", "upwards", "downwards"]}}'::jsonb, '{"blanks": {"B1": "360", "B2": "1"}}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:fib:aca9d3b2', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'fib', 'fib', 2, '{"question": "To find where a curve meets the \\( x \\)-axis you set \\( y = \\) ___B1___ and solve; these values are the ___B2___ of the function.", "blankOptions": {"B1": ["180", "0", "upwards", "3"], "B2": ["touch", "roots", "draw", "3"]}}'::jsonb, '{"blanks": {"B1": "0", "B2": "roots"}}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:fib:981197c4', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'fib', 'fib', 2, '{"question": "The cubic \\( y = (x-1)(x+2)(x-4) \\) has ___B1___ real roots; a repeated factor makes the curve ___B2___ the \\( x \\)-axis instead of crossing it.", "blankOptions": {"B1": ["3", "180", "downwards", "1"], "B2": ["draw", "touch", "360", "1"]}}'::jsonb, '{"blanks": {"B1": "3", "B2": "touch"}}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:fib:7a13ac1e', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'fib', 'fib', 1, '{"question": "The graph of \\( y = \\tan x \\) has vertical asymptotes and repeats every ___B1___ degrees.", "blankOptions": {"B1": ["180", "upwards", "touch", "3"]}}'::jsonb, '{"blanks": {"B1": "180"}}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:match:b490def6', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “\\( y = mx + c \\)”?", "options": ["The point \\( (0,\\ k) \\)", "Exponential growth with asymptote \\( y = 0 \\)", "A wave from \\( 0 \\), peak \\( 1 \\) at \\( 90^\\circ \\), period \\( 360^\\circ \\)", "A straight line with gradient \\( m \\) and \\( y \\)-intercept \\( c \\)"]}'::jsonb, '{"answer": 3, "explain": "“\\( y = mx + c \\)” means: A straight line with gradient \\( m \\) and \\( y \\)-intercept \\( c \\)"}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:match:7108c23a', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “\\( y = x^2 - 4 \\)”?", "options": ["Accurate points on a grid, joined smoothly", "Period \\( 180^\\circ \\), with asymptotes at \\( 90^\\circ \\) and \\( 270^\\circ \\)", "A cubic with three real roots", "An upward parabola crossing the \\( x \\)-axis at \\( \\pm 2 \\)"]}'::jsonb, '{"answer": 3, "explain": "“\\( y = x^2 - 4 \\)” means: An upward parabola crossing the \\( x \\)-axis at \\( \\pm 2 \\)"}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:match:9609c8be', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “\\( y = -x^2 + 1 \\)”?", "options": ["A graphical solution of the equation setting them equal", "Exponential growth with asymptote \\( y = 0 \\)", "An upward parabola crossing the \\( x \\)-axis at \\( \\pm 2 \\)", "A downward parabola with a maximum turning point"]}'::jsonb, '{"answer": 3, "explain": "“\\( y = -x^2 + 1 \\)” means: A downward parabola with a maximum turning point"}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:match:c6cd3ca3', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “\\( y = (x-1)(x+1)(x-3) \\)”?", "options": ["A downward parabola with a maximum turning point", "Exponential growth with asymptote \\( y = 0 \\)", "A cubic with three real roots", "A wave from \\( 0 \\), peak \\( 1 \\) at \\( 90^\\circ \\), period \\( 360^\\circ \\)"]}'::jsonb, '{"answer": 2, "explain": "“\\( y = (x-1)(x+1)(x-3) \\)” means: A cubic with three real roots"}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:match:ee675e63', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “\\( y = (x-2)^2(x+1) \\)”?", "options": ["Freehand graph of the main features, not to scale", "A straight line with gradient \\( m \\) and \\( y \\)-intercept \\( c \\)", "A cubic that touches the axis at \\( x = 2 \\)", "The point \\( (0,\\ k) \\)"]}'::jsonb, '{"answer": 2, "explain": "“\\( y = (x-2)^2(x+1) \\)” means: A cubic that touches the axis at \\( x = 2 \\)"}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:match:30153a4c', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “\\( y = \\sin x \\)”?", "options": ["Freehand graph of the main features, not to scale", "An upward parabola crossing the \\( x \\)-axis at \\( \\pm 2 \\)", "A wave from \\( 0 \\), peak \\( 1 \\) at \\( 90^\\circ \\), period \\( 360^\\circ \\)", "Exponential decay towards \\( y = 0 \\)"]}'::jsonb, '{"answer": 2, "explain": "“\\( y = \\sin x \\)” means: A wave from \\( 0 \\), peak \\( 1 \\) at \\( 90^\\circ \\), period \\( 360^\\circ \\)"}'::jsonb),
('additional-maths:3-3-sketching-and-plotting-graphs:match:de636f69', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “\\( y = \\cos x \\)”?", "options": ["The point \\( (0,\\ k) \\)", "A wave starting at its maximum \\( 1 \\) when \\( x = 0^\\circ \\)", "A cubic that touches the axis at \\( x = 2 \\)", "A cubic with three real roots"]}'::jsonb, '{"answer": 1, "explain": "“\\( y = \\cos x \\)” means: A wave starting at its maximum \\( 1 \\) when \\( x = 0^\\circ \\)"}'::jsonb),
