('additional-maths:3-3-sketching-and-plotting-graphs:match:74b55225', 'additional-maths', 'additional-maths:3-3-sketching-and-plotting-graphs', '3.3 Sketching and Plotting Graphs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “\\( y = k a^x,\\ a>1 \\)”?", "options": ["Exponential growth with asymptote \\( y = 0 \\)", "A wave starting at its maximum \\( 1 \\) when \\( x = 0^\\circ \\)", "Period \\( 180^\\circ \\), with asymptotes at \\( 90^\\circ \\) and \\( 270^\\circ \\)", "Freehand graph of the main features, not to scale"]}'::jsonb, '{"answer": 0, "explain": "“\\( y = k a^x,\\ a>1 \\)” means: Exponential growth with asymptote \\( y = 0 \\)"}'::jsonb),
